Here's a minimal API endpoint that accepts multiple image files plus a text description via multipart form data:

```csharp
using Microsoft.AspNetCore.Http.Features;

var builder = WebApplication.CreateBuilder(args);

// Increase the max request body size to 50MB
builder.WebHost.ConfigureKestrel(options =>
{
    options.Limits.MaxRequestBodySize = 50 * 1024 * 1024;
});

var app = builder.Build();

app.MapPost("/upload", async (HttpRequest request) =>
{
    // Ensure it's a multipart form request
    if (!request.HasFormContentType)
        return Results.BadRequest("Expected a multipart form request.");

    var form = await request.ReadFormAsync();

    var description = form["description"].ToString();
    var files = form.Files.GetFiles("images");

    if (files.Count == 0)
        return Results.BadRequest("No image files provided.");

    var uploadPath = Path.Combine(Directory.GetCurrentDirectory(), "uploads");
    Directory.CreateDirectory(uploadPath);

    var savedFiles = new List<string>();

    foreach (var file in files)
    {
        // Validate content type
        if (!file.ContentType.StartsWith("image/"))
            return Results.BadRequest($"File '{file.FileName}' is not an image.");

        var fileName = $"{Guid.NewGuid()}{Path.GetExtension(file.FileName)}";
        var filePath = Path.Combine(uploadPath, fileName);

        await using var stream = new FileStream(filePath, FileMode.Create);
        await file.CopyToAsync(stream);

        savedFiles.Add(fileName);
    }

    return Results.Ok(new
    {
        Description = description,
        FileCount = savedFiles.Count,
        FileNames = savedFiles
    });
})
.DisableAntiforgery() // Required for minimal APIs accepting form data without a token
.WithRequestFormLimits(multipartBodyLengthLimit: 50 * 1024 * 1024);

app.Run();
```

**Key points:**

- `ConfigureKestrel` raises the request body limit to 50 MB.
- `.WithRequestFormLimits(...)` sets the multipart-specific limit to match.
- `.DisableAntiforgery()` is needed since there's no antiforgery token in API scenarios.
- Files are expected in a form field named `images`; the description in a field named `description`.

**Example `curl` call:**

```bash
curl -X POST http://localhost:5000/upload \
  -F "description=My vacation photos" \
  -F "images=@photo1.jpg" \
  -F "images=@photo2.png"
```
